299	function parseMasterLog(filePath: string): ParsedFact[] {
300	  if (!existsSync(filePath)) return [];
301	  const raw = readFileSync(filePath, "utf8");
302	  const results: ParsedFact[] = [];
303	  for (const line of raw.split(/\r?\n/)) {
304	    // Format: "- [2026-05-16T10:00:00.000Z] fact text here"
305	    const match = line.match(/^\s*-\s*\[([^\]]+)\]\s*(.+)$/);
306	    if (!match) continue;
307	    const createdAt = match[1];
308	    const text = match[2].trim();
309	    if (!text) continue;
310	    const topic = classifyFact(text) || "misc";
311	    results.push({ text, hash: contentHash(text), topic, createdAt });
312	  }
313	  return results;
314	}
