324	function fts5Search(query: string): FtsHit[] {
325	  if (!db) return [];
326	  // Escape FTS5 special chars and build a simple query
327	  const escaped = query.replace(/['"*(){}[\]^~\\:]/g, " ").trim();
328	  if (!escaped) return [];
329	  try {
330	    const rows = db
331	      .prepare(
332	        `SELECT f.content_hash as hash, f.text, f.topic, f.created_at as createdAt,
333	                rank * -1 as score
334	         FROM facts_fts fts
335	         JOIN facts f ON f.content_hash = fts.content_hash
336	         WHERE facts_fts MATCH ?
337	         ORDER BY rank
338	         LIMIT 50`,
339	      )
340	      .all(escaped) as FtsHit[];
341	
342	    // Normalize BM25 scores to 0-1 range
343	    if (rows.length === 0) return [];
344	    const maxScore = Math.max(...rows.map((r) => r.score), 1);
345	    return rows.map((r) => ({ ...r, score: r.score / maxScore }));
346	  } catch {
347	    // FTS5 match can throw on malformed queries
348	    return [];
349	  }
350	}
