360	async function vectorSearch(queryVec: Float32Array): Promise<VectorHit[]> {
361	  if (!db) return [];
362	  // Get all facts that have cached embeddings
363	  const rows = db
364	    .prepare(
365	      `SELECT f.content_hash as hash, f.text, f.topic, f.created_at as createdAt, ec.vector
366	       FROM facts f
367	       JOIN embedding_cache ec ON ec.content_hash = f.content_hash`,
368	    )
369	    .all() as Array<{ hash: string; text: string; topic: string; createdAt: string; vector: Buffer }>;
370	
371	  const hits: VectorHit[] = [];
