374	    const score = cosineSim(queryVec, vec);
375	    if (score > 0.1) {
376	      hits.push({ hash: row.hash, text: row.text, topic: row.topic, createdAt: row.createdAt, score });
377	    }
378	  }
379	  return hits;
380	}
